  1→import { componentCatalog } from "reachat";
  2→import { useState } from "react";
  3→import type { ExtractableKind } from "../shared/chat-component-definitions";
  4→import {
  5→  chatComponentDefinitions,
  6→  type EntityCardProps,
  7→  type ExtractionSummaryProps,
  8→  type WorkItemSuggestionProps,
  9→  type WorkItemSuggestionListProps,
 10→} from "../shared/chat-component-definitions";
 11→import { InlineRelationshipGraph } from "./components/chat/InlineRelationshipGraph";
 12→import { CategoryBadge } from "./components/graph/CategoryBadge";
 13→import { useViewState } from "./stores/view-state";
 14→import { useWorkspaceState } from "./stores/workspace-state";
 15→
 16→const kindLabelByKind: Record<ExtractableKind, string> = {
 17→  project: "Project",
 18→  person: "Person",
 19→  feature: "Feature",
 20→  task: "Task",
 21→  decision: "Decision",
 22→  question: "Question",
 23→};
 24→
 25→function GraphLinkIcon() {
 26→  return (
 27→    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
 28→      <circle cx="6" cy="6" r="3" />
 29→      <circle cx="18" cy="6" r="3" />
 30→      <circle cx="12" cy="18" r="3" />
 31→      <line x1="8.5" y1="7.5" x2="10.5" y2="16" />
 32→      <line x1="15.5" y1="7.5" x2="13.5" y2="16" />
 33→    </svg>
 34→  );
 35→}
 36→
 37→function EntityCard(props: EntityCardProps) {
 38→  const navigateToGraph = useViewState((s) => s.navigateToGraph);
 39→
 40→  function handleGraphClick() {
 41→    if (!props.entityId) return;
 42→    navigateToGraph(props.entityId);
 43→    window.location.pathname = "/graph";
 44→  }
 45→
 46→  return (
 47→    <article className="entity-card">
 48→      <div className="entity-card-header">
 49→        <div style={{ display: "flex", alignItems: "center", gap: "0.3rem" }}>
 50→          <span className="entity-kind">{kindLabelByKind[props.kind]}</span>
 51→          {props.category ? <CategoryBadge category={props.category} /> : undefined}
 52→        </div>
 53→        <div style={{ display: "flex", alignItems: "center", gap: "0.3rem" }}>
 54→          {props.entityId ? (
 55→            <button
 56→              type="button"
 57→              className="entity-card-graph-link"
 58→              title="View in graph"
 59→              onClick={handleGraphClick}
 60→            >
 61→              <GraphLinkIcon />
 62→            </button>
 63→          ) : undefined}
 64→          <span className="entity-status">{props.status}</span>
 65→        </div>
 66→      </div>
 67→      <p className="entity-name">{props.name}</p>
 68→      <p className="entity-confidence">Confidence {props.confidence.toFixed(2)}</p>
 69→    </article>
 70→  );
 71→}
 72→
 73→function ExtractionSummary(props: ExtractionSummaryProps) {
 74→  return (
 75→    <section className="extraction-summary">
 76→      <p className="extraction-summary-title">{props.title}</p>
 77→      <div className="extraction-summary-grid">
 78→        {props.entities.map((entity) => (
 79→          <EntityCard
 80→            key={`${entity.kind}:${entity.name.toLowerCase()}`}
 81→            kind={entity.kind}
 82→            name={entity.name}
 83→            confidence={entity.confidence}
 84→            status={entity.status}
 85→            entityId={entity.entityId}
 86→            category={entity.category}
 87→          />
 88→        ))}
 89→      </div>
 90→      <p className="extraction-summary-meta">{props.relationshipCount} high-confidence relationships detected</p>
 91→    </section>
 92→  );
 93→}
 94→
 95→type WorkItemStatus = "pending" | "accepting" | "accepted" | "dismissed";
 96→
 97→async function acceptWorkItem(
 98→  workspaceId: string,
 99→  item: WorkItemSuggestionProps,
100→): Promise<{ entityId: string }> {
101→  const response = await fetch(`/api/workspaces/${workspaceId}/work-items/accept`, {
102→    method: "POST",
103→    headers: { "Content-Type": "application/json" },
104→    body: JSON.stringify({
105→      kind: item.kind,
106→      title: item.title,
107→      rationale: item.rationale,
108→      ...(item.project ? { project: item.project } : {}),
109→      ...(item.priority ? { priority: item.priority } : {}),
110→      ...(item.category ? { category: item.category } : {}),
111→    }),
112→  });
113→  if (!response.ok) {
114→    throw new Error(`accept failed: ${response.status}`);
115→  }
116→  return response.json();
117→}
118→
119→function WorkItemSuggestion(props: WorkItemSuggestionProps) {
120→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
121→  const [status, setStatus] = useState<WorkItemStatus>("pending");
122→
123→  async function handleAccept() {
124→    if (!workspaceId || status !== "pending") return;
125→    setStatus("accepting");
126→    try {
127→      await acceptWorkItem(workspaceId, props);
128→      setStatus("accepted");
129→    } catch {
130→      setStatus("pending");
131→    }
132→  }
133→
134→  function handleDismiss() {
135→    setStatus("dismissed");
136→  }
137→
138→  if (status === "dismissed") return undefined;
139→
140→  const isDuplicate = props.possibleDuplicateId !== undefined;
141→
142→  return (
143→    <article className={`work-item-suggestion ${status === "accepted" ? "work-item-suggestion--accepted" : ""}`}>
144→      <div className="work-item-suggestion-header">
145→        <div style={{ display: "flex", alignItems: "center", gap: "0.3rem" }}>
146→          <span className="entity-kind">{props.kind === "task" ? "Task" : "Feature"}</span>
147→          {props.category ? <CategoryBadge category={props.category} /> : undefined}
148→          {props.priority ? <span className="work-item-priority">{props.priority}</span> : undefined}
149→        </div>
150→        {status === "accepted" ? (
151→          <span className="work-item-accepted-badge">Accepted</span>
152→        ) : (
153→          <div className="work-item-actions">
154→            <button
155→              type="button"
156→              className="work-item-btn work-item-btn--accept"
157→              onClick={handleAccept}
158→              disabled={status === "accepting"}
159→            >
160→              {status === "accepting" ? "..." : "Accept"}
161→            </button>
162→            <button
163→              type="button"
164→              className="work-item-btn work-item-btn--dismiss"
165→              onClick={handleDismiss}
166→            >
167→              Dismiss
168→            </button>
169→          </div>
170→        )}
171→      </div>
172→      <p className="entity-name">{props.title}</p>
173→      <p className="work-item-rationale">{props.rationale}</p>
174→      {isDuplicate ? (
175→        <p className="work-item-duplicate-hint">
176→          Similar to existing: {props.possibleDuplicateName} ({((props.possibleDuplicateSimilarity ?? 0) * 100).toFixed(0)}% match)
177→        </p>
178→      ) : undefined}
179→      {props.project ? <p className="work-item-project">Project: {props.project}</p> : undefined}
180→    </article>
181→  );
182→}
183→
184→function WorkItemSuggestionList(props: WorkItemSuggestionListProps) {
185→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
186→  const [allStatus, setAllStatus] = useState<"idle" | "accepting">("idle");
187→  const [dismissedAll, setDismissedAll] = useState(false);
188→
189→  async function handleAcceptAll() {
190→    if (!workspaceId || allStatus === "accepting") return;
191→    setAllStatus("accepting");
192→    try {
193→      await Promise.all(props.items.map((item) => acceptWorkItem(workspaceId, item)));
194→    } catch {
195→      // individual items handle their own state
196→    }
197→    setAllStatus("idle");
198→  }
199→
200→  function handleDismissAll() {
201→    setDismissedAll(true);
202→  }
203→
204→  if (dismissedAll) return undefined;
205→
206→  return (
207→    <section className="work-item-suggestion-list">
208→      <div className="work-item-suggestion-list-header">
209→        <p className="extraction-summary-title">{props.title}</p>
210→        <div className="work-item-actions">
211→          <button
212→            type="button"
213→            className="work-item-btn work-item-btn--accept"
214→            onClick={handleAcceptAll}
215→            disabled={allStatus === "accepting"}
216→          >
217→            {allStatus === "accepting" ? "Accepting..." : "Accept All"}
218→          </button>
219→          <button
220→            type="button"
221→            className="work-item-btn work-item-btn--dismiss"
222→            onClick={handleDismissAll}
223→          >
224→            Dismiss All
225→          </button>
226→        </div>
227→      </div>
228→      <div className="extraction-summary-grid">
229→        {props.items.map((item) => (
230→          <WorkItemSuggestion key={`${item.kind}:${item.title}`} {...item} />
231→        ))}
232→      </div>
233→    </section>
234→  );
235→}
236→
237→export const chatComponentCatalog = componentCatalog({
238→  EntityCard: {
239→    ...chatComponentDefinitions.EntityCard,
240→    component: EntityCard as any,
241→  },
242→  ExtractionSummary: {
243→    ...chatComponentDefinitions.ExtractionSummary,
244→    component: ExtractionSummary as any,
245→  },
246→  WorkItemSuggestion: {
247→    ...chatComponentDefinitions.WorkItemSuggestion,
248→    component: WorkItemSuggestion as any,
249→  },
250→  WorkItemSuggestionList: {
251→    ...chatComponentDefinitions.WorkItemSuggestionList,
252→    component: WorkItemSuggestionList as any,
253→  },
254→  InlineRelationshipGraph: {
255→    ...chatComponentDefinitions.InlineRelationshipGraph,
256→    component: InlineRelationshipGraph as any,
257→  },
258→});
