 21→export async function runChatAgent(input: {
 22→  surreal: Surreal;
 23→  model: any;
 24→  pmAgentModel: any;
 25→  analyticsAgentModel: any;
 26→  analyticsSurreal: Surreal;
 27→  embeddingModel: any;
 28→  embeddingDimension: number;
 29→  extractionModelId: string;
 30→  extractionModel: any;
 31→  extractionStoreThreshold: number;
 32→  conversationRecord: RecordId<"conversation", string>;
 33→  workspaceRecord: RecordId<"workspace", string>;
 34→  currentMessageRecord: RecordId<"message", string>;
 35→  latestUserText: string;
 36→  workspaceOwnerRecord?: RecordId<"person", string>;
 37→  inheritedEntityIds?: RecordId[];
 38→  discussesRecord?: RecordId;
 39→  messages: ConversationMessage[];
 40→  isOnboarding?: boolean;
 41→  onboardingState?: OnboardingState;
 42→  onToken: (token: string) => Promise<void> | void;
 43→}): Promise<ChatAgentResult> {
 44→  const context = await buildChatContext({
 45→    surreal: input.surreal,
 46→    conversationRecord: input.conversationRecord,
 47→    workspaceRecord: input.workspaceRecord,
 48→    ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 49→      ? { inheritedEntityIds: input.inheritedEntityIds }
 50→      : {}),
 51→    ...(input.discussesRecord ? { discussesRecord: input.discussesRecord } : {}),
 52→  });
 53→
 54→  const system = buildSystemPrompt(context, {
 55→    isOnboarding: input.isOnboarding,
 56→    onboardingState: input.onboardingState,
 57→  });
 58→
 59→  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
 60→    role: message.role,
 61→    content: message.text,
 62→  }));
 63→
 64→  const result = streamText({
 65→    model: input.model,
 66→    system,
 67→    messages: modelMessages,
 68→    tools: createChatAgentTools({
 69→      surreal: input.surreal,
 70→      pmAgentModel: input.pmAgentModel,
 71→      analyticsAgentModel: input.analyticsAgentModel,
 72→      analyticsSurreal: input.analyticsSurreal,
 73→      embeddingModel: input.embeddingModel,
 74→      embeddingDimension: input.embeddingDimension,
 75→      extractionModelId: input.extractionModelId,
 76→      extractionModel: input.extractionModel,
 77→      extractionStoreThreshold: input.extractionStoreThreshold,
 78→    }),
 79→    experimental_context: {
 80→      actor: "chat_agent",
 81→      workspaceRecord: input.workspaceRecord,
 82→      conversationRecord: input.conversationRecord,
 83→      currentMessageRecord: input.currentMessageRecord,
 84→      latestUserText: input.latestUserText,
 85→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
 86→    },
 87→    stopWhen: stepCountIs(5),
 88→  });
 89→
 90→  let text = "";
 91→  const collectedEntities: CollectedEntity[] = [];
 92→  const collectedRelationships: CollectedRelationship[] = [];
 93→
 94→  for await (const part of result.fullStream) {
 95→    if (part.type === "text-delta") {
 96→      text = `${text}${part.text}`;
 97→      await input.onToken(part.text);
 98→      continue;
 99→    }
100→

100→
101→    if (part.type === "tool-result") {
102→      const toolResult = part.output as Record<string, unknown> | undefined;
103→      if (toolResult) {
104→        if (Array.isArray(toolResult.extracted_entities)) {
105→          collectedEntities.push(...(toolResult.extracted_entities as CollectedEntity[]));
106→        }
107→        if (Array.isArray(toolResult.extracted_relationships)) {
108→          collectedRelationships.push(...(toolResult.extracted_relationships as CollectedRelationship[]));
109→        }
110→      }
111→    }
112→  }
113→
114→  if (text.trim().length === 0) {
115→    text = await result.text;
116→  }
117→
118→  // Post-process: inject entity:// links for entity names mentioned in the response.
119→  const linked = injectEntityLinks(text, context);
120→  if (linked !== text) {
121→    // Re-send the full linked text as a replacement.
122→    // The SSE stream already sent raw text; the persisted version will have links.
123→    text = linked;
124→  }
125→
126→  return {
127→    text: text.trim(),
128→    collectedEntities,
129→    collectedRelationships,
130→  };
131→}
