133→export const runGraphAwareChat = runChatAgent;
134→
135→type KnownEntity = { entityId: string; kind: string; name: string };
136→
137→/**
138→ * Replace entity name mentions in response text with markdown links:
139→ *   "Model for Extraction Pipeline" → "[Model for Extraction Pipeline](entity://decision:uuid)"
140→ *
141→ * Matches longest names first to avoid partial replacement.
142→ * Only replaces the first occurrence of each entity name.
143→ */
144→function injectEntityLinks(text: string, context: ChatContext): string {
145→  const entities: KnownEntity[] = [];
146→
147→  for (const project of context.workspaceSummary.projects) {
148→    entities.push({ entityId: `project:${project.id}`, kind: "project", name: project.name });
149→  }
150→  for (const decision of context.workspaceSummary.recentDecisions) {
151→    entities.push({ entityId: `decision:${decision.id}`, kind: "decision", name: decision.name });
152→  }
153→  for (const question of context.workspaceSummary.openQuestions) {
154→    entities.push({ entityId: `question:${question.id}`, kind: "question", name: question.name });
155→  }
156→
157→  // Sort longest name first so "Agent-Native Business OS" matches before "Agent"
158→  entities.sort((a, b) => b.name.length - a.name.length);
159→
160→  const replaced = new Set<string>();
161→  let result = text;
162→
163→  for (const entity of entities) {
164→    if (entity.name.length < 3) continue;
165→    if (replaced.has(entity.entityId)) continue;
166→
167→    // Case-insensitive match, but only replace the first occurrence.
168→    // Skip if the name is already inside a markdown link.
169→    const idx = result.toLowerCase().indexOf(entity.name.toLowerCase());
170→    if (idx === -1) continue;
171→
172→    // Check if already inside a markdown link: [...](...)
173→    const before = result.slice(0, idx);
174→    if (before.lastIndexOf("[") > before.lastIndexOf("]")) continue;
175→
176→    const matched = result.slice(idx, idx + entity.name.length);
177→    const link = `[${matched}](#entity/${entity.entityId})`;
178→    result = `${result.slice(0, idx)}${link}${result.slice(idx + entity.name.length)}`;
179→    replaced.add(entity.entityId);
180→  }
181→
182→  return result;
183→}
