 17→export async function processChatMessage(input: {
 18→  deps: ServerDependencies;
 19→  conversationId: string;
 20→  messageId: string;
 21→  workspaceRecord: RecordId<"workspace", string>;
 22→  userMessageRecord: RecordId<"message", string>;
 23→  userText: string;
 24→  attachment?: IncomingAttachment;
 25→  onboardingAction?: OnboardingAction;
 26→}): Promise<void> {
 27→  const startedAt = performance.now();
 28→  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
 29→    conversationId: input.conversationId,
 30→    messageId: input.messageId,
 31→    workspaceId: input.workspaceRecord.id as string,
 32→    hasAttachment: input.attachment !== undefined,
 33→  });
 34→
 35→  try {
 36→    const now = new Date();
 37→    const conversationRecord = new RecordId("conversation", input.conversationId);
 38→    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
 39→    if (!workspace) {
 40→      throw new Error("workspace not found");
 41→    }
 42→
 43→    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
 44→    if (!conversation) {
 45→      throw new Error("conversation not found");
 46→    }
 47→
 48→    // Check if this conversation is a branch and load inherited context
 49→    const branchChain = await loadBranchChain(input.deps.surreal, input.conversationId);
 50→    const isBranch = branchChain.length > 0;
 51→
 52→    let inheritedEntityIds: RecordId[] | undefined;
 53→    let assistantContextRows: Array<{ id: RecordId<"message", string>; role: "user" | "assistant"; text: string; createdAt: Date | string }>;
 54→
 55→    if (isBranch) {
 56→      // For branches, load full message history including inherited messages
 57→      const allMessages = await loadMessagesWithInheritance(input.deps.surreal, input.conversationId, 30);
 58→      assistantContextRows = allMessages
 59→        .map((m) => ({
 60→          id: new RecordId("message", m.id),
 61→          role: m.role,
 62→          text: m.text,
 63→          createdAt: m.createdAt,
 64→        }))
 65→        .slice(-10);
 66→
 67→      // Derive inherited entity IDs from extraction_relations on inherited messages
 68→      const inheritedMsgIds = allMessages
 69→        .filter((m) => m.inherited)
 70→        .map((m) => new RecordId("message", m.id));
 71→
 72→      if (inheritedMsgIds.length > 0) {
 73→        const [entityRows] = await input.deps.surreal
 74→          .query<[Array<{ out: RecordId }>]>(
 75→            "SELECT DISTINCT out FROM extraction_relation WHERE `in` IN $msgIds LIMIT 30;",
 76→            { msgIds: inheritedMsgIds },
 77→          )
 78→          .collect<[Array<{ out: RecordId }>]>();
 79→        inheritedEntityIds = entityRows.map((r) => r.out);
 80→      }
 81→    } else {
 82→      assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
 83→    }
 84→
 85→    const workspaceProjects = await loadWorkspaceProjects(input.deps.surreal, input.workspaceRecord);
 86→    const workspaceProjectNames = workspaceProjects.map((project) => project.name);
 87→    const persistedEntities: ExtractedEntity[] = [];
 88→    const persistedRelationships: ExtractedRelationship[] = [];
 89→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
 90→    const extractedTools: string[] = [];
 91→    const unresolvedAssigneeNames = new Set<string>();
 92→
 93→    // Attachment extraction stays automatic — document ingestion is intentional
 94→    if (input.attachment) {
 95→      const ingestion = await ingestAttachment({
 96→        surreal: input.deps.surreal,
 97→        extractionModel: input.deps.extractionModel,
 98→        embeddingModel: input.deps.embeddingModel,
 99→        embeddingDimension: input.deps.config.embeddingDimension,
100→        extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
101→        extractionModelId: input.deps.config.extractionModelId,
102→        workspaceRecord: input.workspaceRecord,
103→        conversationRecord,
104→        userMessageRecord: input.userMessageRecord,
105→        attachment: input.attachment,
106→        workspaceName: workspace.name,
107→        projectNames: workspaceProjectNames,
108→        now,
109→        onChunkResult: (chunkResult) => {
110→          if (chunkResult.entities.length > 0 || chunkResult.relationships.length > 0) {
111→            input.deps.sse.emitEvent(input.messageId, {
112→              type: "extraction",
113→              messageId: input.messageId,
114→              entities: chunkResult.entities,
115→              relationships: chunkResult.relationships,
116→            });
117→          }
118→        },
119→      });
120→
121→      persistedEntities.push(...ingestion.entities);
122→      persistedRelationships.push(...ingestion.relationships);
123→      embeddingTargets.push(...ingestion.embeddingTargets);
124→      extractedTools.push(...ingestion.tools);
125→      for (const unresolvedName of ingestion.unresolvedAssigneeNames) {
126→        unresolvedAssigneeNames.add(unresolvedName);
127→      }
128→    }
129→
130→    if (extractedTools.length > 0) {
131→      await appendExtractedTools(input.deps.surreal, input.workspaceRecord, extractedTools, now);
132→    }
133→
134→    const onboardingBefore = workspace.onboarding_complete
135→      ? "complete"
136→      : workspace.onboarding_summary_pending
137→        ? "summary_pending"
138→        : "active";
139→
140→    const onboardingAfter = await transitionOnboardingState({
141→      surreal: input.deps.surreal,
142→      workspaceRecord: input.workspaceRecord,
143→      workspace,
144→      onboardingAction: input.onboardingAction,
145→      now,
146→    });
147→
148→    // Always run chat agent — it handles both onboarding and post-onboarding
149→    const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
150→      surreal: input.deps.surreal,
151→      workspaceRecord: input.workspaceRecord,
152→    });
153→
154→    const graphAwareResponse = await runChatAgent({
155→      surreal: input.deps.surreal,
156→      model: input.deps.chatAgentModel,
157→      pmAgentModel: input.deps.pmAgentModel,
158→      analyticsAgentModel: input.deps.analyticsAgentModel,
159→      analyticsSurreal: input.deps.analyticsSurreal,
160→      embeddingModel: input.deps.embeddingModel,
161→      embeddingDimension: input.deps.config.embeddingDimension,
162→      extractionModelId: input.deps.config.extractionModelId,
163→      extractionModel: input.deps.extractionModel,
164→      extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
165→      conversationRecord,
166→      workspaceRecord: input.workspaceRecord,
167→      currentMessageRecord: input.userMessageRecord,
168→      latestUserText: input.userText,
169→      isOnboarding: onboardingAfter !== "complete",
170→      onboardingState: onboardingAfter,
171→      ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
172→      ...(inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : {}),
173→      ...(conversation.discusses ? { discussesRecord: conversation.discusses } : {}),
174→      messages: assistantContextRows.map((row) => ({
175→        role: row.role,
176→        text: row.text,
177→      })),
178→      onToken: async (token) => {
179→        input.deps.sse.emitEvent(input.messageId, {
180→          type: "token",
181→          messageId: input.messageId,
182→          token,
183→        });
184→      },
185→    });
186→
187→    let assistantText = graphAwareResponse.text.trim();
188→    persistedEntities.push(...graphAwareResponse.collectedEntities);
189→    persistedRelationships.push(...graphAwareResponse.collectedRelationships);
190→
191→    const unresolvedAssigneeSuggestions = [...unresolvedAssigneeNames].map(
192→      (name) => `You mentioned ${name} - want to add them to workspace people?`,
193→    );
194→    const assistantSuggestions = sanitizeAssistantSuggestions(unresolvedAssigneeSuggestions, 3);
195→
196→    // Post-response hooks (entities now created during chat agent execution)
197→    await refreshConversationTouchedBy(input.deps.surreal, conversationRecord);
198→    await maybeUpgradeConversationTitle(input.deps.surreal, conversationRecord);
199→
200→    if (assistantText.trim().length === 0) {

200→    if (assistantText.trim().length === 0) {
201→      assistantText = "I could not generate a response for that request.";
202→    }
203→
204→    const assistantMessageRecord = new RecordId("message", input.messageId);
205→    await input.deps.surreal.create(assistantMessageRecord).content({
206→      conversation: conversationRecord,
207→      role: "assistant",
208→      text: assistantText,
209→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
210→      createdAt: now,
211→    });
212→
213→    await input.deps.surreal.update(conversationRecord).merge({
214→      updatedAt: now,
215→    });
216→
217→    void persistEmbeddings({
218→      surreal: input.deps.surreal,
219→      embeddingModel: input.deps.embeddingModel,
220→      embeddingDimension: input.deps.config.embeddingDimension,
221→      assistantMessageRecord,
222→      assistantText,
223→      entities: embeddingTargets,
224→    }).catch(() => undefined);
225→
226→    input.deps.sse.emitEvent(input.messageId, {
227→      type: "extraction",
228→      messageId: input.messageId,
229→      entities: persistedEntities,
230→      relationships: persistedRelationships,
231→    });
232→
233→    if (onboardingBefore !== onboardingAfter) {
234→      input.deps.sse.emitEvent(input.messageId, {
235→        type: "onboarding_state",
236→        messageId: input.messageId,
237→        onboardingState: onboardingAfter,
238→      });
239→    }
240→
241→    input.deps.sse.emitEvent(input.messageId, {
242→      type: "assistant_message",
243→      messageId: input.messageId,
244→      text: assistantText,
245→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
246→    });
247→
248→    input.deps.sse.emitEvent(input.messageId, {
249→      type: "done",
250→      messageId: input.messageId,
251→    });
252→
253→    logInfo("chat.message.process.execution.completed", "Chat message processing execution completed", {
254→      conversationId: input.conversationId,
255→      messageId: input.messageId,
256→      workspaceId: input.workspaceRecord.id as string,
257→      entityCount: persistedEntities.length,
258→      relationshipCount: persistedRelationships.length,
259→      durationMs: elapsedMs(startedAt),
260→    });
261→  } catch (error) {
262→    logError("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
263→      conversationId: input.conversationId,
264→      messageId: input.messageId,
265→      workspaceId: input.workspaceRecord.id as string,
266→      durationMs: elapsedMs(startedAt),
267→    });
268→    const errorText = userFacingError(error, "chat processing failed");
269→    input.deps.sse.emitEvent(input.messageId, {
270→      type: "error",
271→      messageId: input.messageId,
272→      error: errorText,
273→    });
274→  }
275→}
