154→  async function loadConversation(wsId: string, conversationId: string) {
155→    try {
156→      const response = await fetch(
157→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
158→      );
159→      if (!response.ok) {
160→        const body = await response.text();
161→        setErrorMessage(body);
162→        return;
163→      }
164→
165→      const payload = (await response.json()) as WorkspaceConversationResponse;
166→      const conversations: Session["conversations"] = [];
167→      let latestSuggestions: string[] = [];
168→      const inheritedIds = new Set<string>();
169→
170→      for (const message of payload.messages) {
171→        if (message.role === "user") {
172→          conversations.push({
173→            id: message.id,
174→            question: message.text,
175→            createdAt: new Date(message.createdAt),
176→          });
177→          if (message.inherited) {
178→            inheritedIds.add(message.id);
179→          }
180→          continue;
181→        }
182→
183→        const last = conversations[conversations.length - 1];
184→        if (last && !last.response) {
185→          last.response = message.text;
186→          last.updatedAt = new Date(message.createdAt);
187→          latestSuggestions =
188→            message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
189→          if (message.inherited) {
190→            inheritedIds.add(last.id);
191→          }
192→          continue;
193→        }
194→
195→        conversations.push({
196→          id: `assistant-${message.id}`,
197→          question: "",
198→          response: message.text,
199→          createdAt: new Date(message.createdAt),
200→        });
201→        if (message.inherited) {
202→          inheritedIds.add(`assistant-${message.id}`);
203→        }
204→        latestSuggestions =
205→          message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
206→      }
207→
208→      setInheritedMessageIds(inheritedIds);
209→      setSessions([
210→        {
211→          id: "main",
212→          title: workspaceName ?? "Workspace Chat",
213→          createdAt: new Date(),
214→          updatedAt: new Date(),
215→          conversations,
216→        },
217→      ]);
218→
219→      setSuggestions(
220→        latestSuggestions.map((content, index) => ({
221→          id: `conv-suggestion-${index}-${content}`,
222→          content,
223→        })),
224→      );
225→
226→      setActiveConversationId(conversationId);
227→      setBackendConversationId(conversationId);
228→      setConversationDiscussEntity(payload.discussEntity);
229→    } catch (error) {
230→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
231→      setErrorMessage(messageText);
232→    }
233→  }
