342→  async function onSendMessage(
343→    message: string,
344→    options?: { onboardingAction?: OnboardingAction },
345→  ) {
346→    if (isLoading || !workspaceId) {
347→      return;
348→    }
349→
350→    const text = message.trim();
351→    if (!text && !pendingFile) {
352→      return;
353→    }
354→
355→    setErrorMessage(undefined);
356→    setIsLoading(true);
357→    setSuggestions([]);
358→
359→    const clientMessageId = crypto.randomUUID();
360→    const currentAttachment = pendingFile;
361→
362→    setSessions((existing) =>
363→      existing.map((session) =>
364→        session.id === activeSessionId
365→          ? {
366→              ...session,
367→              updatedAt: new Date(),
368→              conversations: [
369→                ...session.conversations,
370→                {
371→                  id: clientMessageId,
372→                  question: text.length > 0 ? text : `Uploaded ${currentAttachment?.name ?? "file"}`,
373→                  createdAt: new Date(),
374→                  ...(currentAttachment
375→                    ? {
376→                        files: [
377→                          {
378→                            name: currentAttachment.name,
379→                            type: currentAttachment.type,
380→                            size: currentAttachment.size,
381→                          },
382→                        ],
383→                      }
384→                    : {}),
385→                },
386→              ],
387→            }
388→          : session,
389→      ),
390→    );
391→
392→    let response: Response;
393→    try {
394→      const includeDiscussEntity = !backendConversationId && discussEntity;
395→
396→      if (currentAttachment) {
397→        const formData = new FormData();
398→        formData.set("clientMessageId", clientMessageId);
399→        formData.set("workspaceId", workspaceId);

400→        formData.set("text", text);
401→        if (backendConversationId) {
402→          formData.set("conversationId", backendConversationId);
403→        }
404→        if (options?.onboardingAction) {
405→          formData.set("onboardingAction", options.onboardingAction);
406→        }
407→        if (includeDiscussEntity) {
408→          formData.set("discussEntityId", discussEntity.id);
409→        }
410→        formData.set("file", currentAttachment);
411→
412→        response = await fetch("/api/chat/messages", {
413→          method: "POST",
414→          body: formData,
415→        });
416→      } else {
417→        response = await fetch("/api/chat/messages", {
418→          method: "POST",
419→          headers: {
420→            "Content-Type": "application/json",
421→          },
422→          body: JSON.stringify({
423→            clientMessageId,
424→            workspaceId,
425→            text,
426→            ...(backendConversationId ? { conversationId: backendConversationId } : {}),
427→            ...(options?.onboardingAction ? { onboardingAction: options.onboardingAction } : {}),
428→            ...(includeDiscussEntity ? { discussEntityId: discussEntity.id } : {}),
429→          }),
430→        });
431→      }
432→    } catch (error) {
433→      const messageText = error instanceof Error ? error.message : "Network error";
434→      setErrorMessage(messageText);
435→      setIsLoading(false);
436→      return;
437→    } finally {
438→      setPendingFile(undefined);
439→    }
440→
441→    if (!response.ok) {
442→      const body = await response.text();
443→      setErrorMessage(body);
444→      setIsLoading(false);
445→      return;
446→    }
447→
448→    const payload = (await response.json()) as ChatMessageResponse;
449→    const isNewConversation = !backendConversationId;
450→    setBackendConversationId(payload.conversationId);
451→    if (isNewConversation) {
452→      setActiveConversationId(payload.conversationId);
453→      if (discussEntity) {
454→        clearDiscussEntity();
455→      }
456→    }
457→
458→    if (streamRef.current) {
459→      streamRef.current.close();
460→      streamRef.current = undefined;
461→    }
462→
463→    let streamedText = "";
464→
465→    const stream = new EventSource(payload.streamUrl);
466→    streamRef.current = stream;
467→
468→    stream.onmessage = (messageEvent) => {
469→      const parsed = JSON.parse(messageEvent.data) as ChatStreamEvent;
470→
471→      if (parsed.type === "token") {
472→        streamedText = `${streamedText}${parsed.token}`;
473→        setSessions((existing) =>
474→          existing.map((session) =>
475→            session.id === activeSessionId
476→              ? {
477→                  ...session,
478→                  conversations: session.conversations.map((conversation) =>
479→                    conversation.id === clientMessageId
480→                      ? {
481→                          ...conversation,
482→                          response: streamedText,
483→                          updatedAt: new Date(),
484→                        }
485→                      : conversation,
486→                  ),
487→                }
488→              : session,
489→          ),
490→        );
491→        return;
492→      }
493→
494→      if (parsed.type === "extraction") {
495→        store.mergeSeedItems(
496→          parsed.entities.map((entity) => ({
497→            id: entity.id,
498→            kind: entity.kind,
499→            text: entity.text,
500→            confidence: entity.confidence,
501→            sourceKind: entity.sourceKind,
502→            sourceId: entity.sourceId,
503→          })),
504→        );
505→        return;
506→      }
507→
508→      if (parsed.type === "assistant_message") {
509→        streamedText = parsed.text;
510→        setSuggestions(
511→          (parsed.suggestions ?? []).map((content, index) => ({
512→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
513→            content,
514→          })),
515→        );
516→        setSessions((existing) =>
517→          existing.map((session) =>
518→            session.id === activeSessionId
519→              ? {
520→                  ...session,
521→                  conversations: session.conversations.map((conversation) =>
522→                    conversation.id === clientMessageId
523→                      ? {
524→                          ...conversation,
525→                          response: streamedText,
526→                          updatedAt: new Date(),
527→                        }
528→                      : conversation,
529→                  ),
530→                }
531→              : session,
532→          ),
533→        );
534→        return;
535→      }
536→
537→      if (parsed.type === "onboarding_seed") {
538→        store.mergeSeedItems(parsed.seeds);
539→        return;
540→      }
541→
542→      if (parsed.type === "onboarding_state") {
543→        store.setOnboardingState(parsed.onboardingState);
544→        return;
545→      }
546→
547→      if (parsed.type === "error") {
548→        setErrorMessage(parsed.error);
549→        setIsLoading(false);
550→        stream.close();
551→        streamRef.current = undefined;
552→        return;
553→      }
554→
555→      if (parsed.type === "done") {
556→        setSessions((existing) =>
557→          existing.map((session) =>
558→            session.id === activeSessionId
559→              ? {
560→                  ...session,
561→                  updatedAt: new Date(),
562→                  conversations: session.conversations.map((conversation) =>
563→                    conversation.id === clientMessageId
564→                      ? {
565→                          ...conversation,
566→                          response: streamedText,
567→                          updatedAt: new Date(),
568→                        }
569→                      : conversation,
570→                  ),
571→                }
572→              : session,
573→          ),
574→        );
575→
576→        setIsLoading(false);
577→        stream.close();
578→        streamRef.current = undefined;
579→
580→        // Refresh sidebar after stream completes
581→        if (workspaceId) {
582→          void refreshSidebar(workspaceId);
583→        }
584→      }
585→    };
586→
587→    stream.onerror = () => {
588→      setErrorMessage("SSE stream disconnected");
589→      setIsLoading(false);
590→      stream.close();
591→      streamRef.current = undefined;
592→    };
593→  }
594→
595→  function onStopMessage() {
596→    if (!streamRef.current) {
597→      return;
598→    }
599→
600→    streamRef.current.close();
601→    streamRef.current = undefined;
602→    setIsLoading(false);
603→  }
604→
605→  return {
606→    sessions,
