119→function WorkItemSuggestion(props: WorkItemSuggestionProps) {
120→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
121→  const [status, setStatus] = useState<WorkItemStatus>("pending");
122→
123→  async function handleAccept() {
124→    if (!workspaceId || status !== "pending") return;
125→    setStatus("accepting");
126→    try {
127→      await acceptWorkItem(workspaceId, props);
128→      setStatus("accepted");
129→    } catch {
130→      setStatus("pending");
131→    }
132→  }
133→
134→  function handleDismiss() {
135→    setStatus("dismissed");
136→  }
137→
138→  if (status === "dismissed") return undefined;
139→
140→  const isDuplicate = props.possibleDuplicateId !== undefined;
141→
142→  return (
143→    <article className={`work-item-suggestion ${status === "accepted" ? "work-item-suggestion--accepted" : ""}`}>
144→      <div className="work-item-suggestion-header">
145→        <div style={{ display: "flex", alignItems: "center", gap: "0.3rem" }}>
146→          <span className="entity-kind">{props.kind === "task" ? "Task" : "Feature"}</span>
147→          {props.category ? <CategoryBadge category={props.category} /> : undefined}
148→          {props.priority ? <span className="work-item-priority">{props.priority}</span> : undefined}
149→        </div>
150→        {status === "accepted" ? (
151→          <span className="work-item-accepted-badge">Accepted</span>
152→        ) : (
153→          <div className="work-item-actions">
154→            <button
155→              type="button"
156→              className="work-item-btn work-item-btn--accept"
157→              onClick={handleAccept}
158→              disabled={status === "accepting"}
159→            >
160→              {status === "accepting" ? "..." : "Accept"}
161→            </button>
162→            <button
163→              type="button"
164→              className="work-item-btn work-item-btn--dismiss"
165→              onClick={handleDismiss}
166→            >
167→              Dismiss
168→            </button>
169→          </div>
170→        )}
171→      </div>
172→      <p className="entity-name">{props.title}</p>
173→      <p className="work-item-rationale">{props.rationale}</p>
174→      {isDuplicate ? (
175→        <p className="work-item-duplicate-hint">
176→          Similar to existing: {props.possibleDuplicateName} ({((props.possibleDuplicateSimilarity ?? 0) * 100).toFixed(0)}% match)
177→        </p>
178→      ) : undefined}
179→      {props.project ? <p className="work-item-project">Project: {props.project}</p> : undefined}
180→    </article>
181→  );
