135→function formatWorkspaceSummary(context: ChatContext): string {
136→  const { projects, recentDecisions, openQuestions, openObservations } = context.workspaceSummary;
137→
138→  const lines: string[] = [];
139→
140→  // Projects: keep names since they're needed for routing
141→  if (projects.length === 0) {
142→    lines.push("- Projects: none");
143→  } else {
144→    lines.push(`- Projects: ${projects.map((p) => p.name).join(", ")}`);
145→  }
146→
147→  // Decisions: count by status
148→  if (recentDecisions.length === 0) {
149→    lines.push("- Decisions: none");
150→  } else {
151→    const statusCounts = new Map<string, number>();
152→    for (const d of recentDecisions) {
153→      statusCounts.set(d.status, (statusCounts.get(d.status) ?? 0) + 1);
154→    }
155→    const breakdown = [...statusCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
156→    lines.push(`- Decisions: ${recentDecisions.length} (${breakdown})`);
157→  }
158→
159→  // Questions: just count
160→  lines.push(`- Open questions: ${openQuestions.length}`);
161→
162→  // Observations: count by severity
163→  if (openObservations.length === 0) {
164→    lines.push("- Observations: none");
165→  } else {
166→    const severityCounts = new Map<string, number>();
167→    for (const o of openObservations) {
168→      severityCounts.set(o.severity, (severityCounts.get(o.severity) ?? 0) + 1);
169→    }
170→    const breakdown = [...severityCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
171→    lines.push(`- Observations: ${openObservations.length} (${breakdown})`);
172→  }
173→
174→  return lines.join("\n");
175→}
